css:
.loader {
  color: var(--loader-color, #0891b2);
  width: 60px;
  aspect-ratio: 1;
  --g: conic-gradient(from -90deg at 10px 10px,currentColor 90deg,#0000 0);
  background: 
    var(--g),
    var(--g) 10px 10px,
    var(--g) 20px 20px;
  background-size: 50% 50%;
  animation: l15 1s infinite;
}
@keyframes l15 {
    90%,100%  {background-position: -30px 30px,-20px 40px,-10px 50px} 
}
